import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Button, Select } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../store/hooks';
import { fpcService } from '../services/fpc/service';
import type { FpcDevSampleDataResultDto } from '../services/fpc/types';
import { getApiErrorMessage } from '../utils/getApiErrorMessage';
import styles from '../pages/Fpc/DailyCashForecastPage/DailyCashForecastPage.module.css';

const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({
  value: String(i + 1),
  label: `Tháng ${i + 1}`,
}));

const yearOptions = (span = 5) => {
  const y = new Date().getFullYear();
  return Array.from({ length: span }, (_, i) => {
    const year = y - 2 + i;
    return { value: String(year), label: String(year) };
  });
};

const REPORT_LINKS = [
  { label: 'Dự báo tiền mặt hàng ngày', url: '/tc/kh/du-bao-tien-mat' },
  { label: 'Tiền mặt hôm nay', url: '/tc/bc/hom-nay' },
  { label: 'Dòng tiền 13 tuần', url: '/tc/kh/dong-tien' },
  { label: 'Kế hoạch so với thực tế', url: '/tc/kh/kh-vs-thuc-te' },
  { label: 'Nhật ký chênh lệch', url: '/tc/bc/nhat-ky-chenh-lech' },
  { label: 'Lợi nhuận và thua lỗ theo chi nhánh', url: '/tc/bc/pnl-chi-nhanh' },
  { label: 'Lợi nhuận và thua lỗ hợp nhất', url: '/tc/bc/pnl-hop-nhat' },
  { label: 'Cân đối kế toán dự phóng', url: '/tc/kh/cdkt-du-phong' },
] as const;

const DEMO_LINKS = [
  { label: 'Báo cáo mẫu Kế hoạch Tài chính (dữ liệu mô phỏng — khách xác nhận)', url: '/tc/fpc/demo' },
  { label: 'Khai báo chi phí (dữ liệu mô phỏng)', url: '/tc/kh/khai-bao-chi-phi' },
  { label: 'Phiếu kế hoạch (dữ liệu mô phỏng)', url: '/tc/kh/phieu-ke-hoach' },
] as const;

const DevFpcSampleDataPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [running, setRunning] = useState(false);
  const [result, setResult] = useState<FpcDevSampleDataResultDto | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    setRunning(true);
    setError(null);
    try {
      const data = await fpcService.generateDevSampleData(Number(month), Number(year));
      setResult(data);
    } catch (e: unknown) {
      const msg = getApiErrorMessage(e, 'Tạo dữ liệu mẫu thất bại');
      setError(msg);
    } finally {
      setRunning(false);
    }
  };

  return (
    <div data-testid="dev-fpc-sample-data-page" style={{ padding: 24, maxWidth: 800 }}>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: 20, fontWeight: 700, margin: '0 0 4px' }}>
          <i className="fas fa-database" style={{ marginRight: 8 }} />
          Tạo dữ liệu mẫu FPC
        </h1>
        <p style={{ margin: 0, fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>
          Dev only — tạo danh mục dòng tiền + phiên bản kế hoạch + dòng dự báo dòng tiền tháng.
          Dữ liệu mô tả <code>[DEMO]</code>. Không ghi đè dữ liệu có sẵn.
        </p>
      </div>

      <div style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: 16, fontWeight: 600, marginBottom: 12 }}>Kỳ dữ liệu</h2>
        <p style={{ margin: '0 0 12px', fontSize: 13, lineHeight: 1.5 }}>
          Chọn tháng và năm để tạo dòng dự báo. Danh mục dòng tiền sẽ được tạo nếu chưa có.
          Phiên bản kế hoạch sẽ được tạo và kích hoạt nếu chưa tồn tại.
        </p>
        <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
          <div>
            <label style={{ display: 'block', marginBottom: 4, fontSize: 13, fontWeight: 500 }}>Tháng</label>
            <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
          </div>
          <div>
            <label style={{ display: 'block', marginBottom: 4, fontSize: 13, fontWeight: 500 }}>Năm</label>
            <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
          </div>
          <div style={{ display: 'flex', alignItems: 'flex-end' }}>
            <Button
              variant="primary"
              data-testid="dev-fpc-sample-data-generate-btn"
              onClick={handleGenerate}
              loading={running}
            >
              Tạo dữ liệu mẫu
            </Button>
          </div>
        </div>
      </div>

      {error && (
        <div style={{ marginBottom: 16, padding: 12, borderRadius: 6, background: '#fff2f0', border: '1px solid #ffccc7' }}>
          <p style={{ margin: 0, fontSize: 13, color: '#cf1322' }}>{error}</p>
        </div>
      )}

      {result && (
        <div data-testid="dev-fpc-sample-data-result" style={{ marginBottom: 24 }}>
          <h2 style={{ fontSize: 16, fontWeight: 600, marginBottom: 8 }}>Kết quả — kỳ {result.month}/{result.year}</h2>
          <p style={{ fontSize: 13 }}>{result.message}</p>
          <div style={{ marginTop: 12, fontSize: 13 }}>
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '2px solid #f0f0f0' }}>
                  <th style={{ textAlign: 'left', padding: '6px 8px' }}>Hạng mục</th>
                  <th style={{ textAlign: 'right', padding: '6px 8px' }}>Số lượng</th>
                </tr>
              </thead>
              <tbody>
                <tr style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '6px 8px' }}>Danh mục dòng tiền (tạo mới)</td>
                  <td style={{ textAlign: 'right', padding: '6px 8px' }}>{result.categoriesCreated}</td>
                </tr>
                <tr style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '6px 8px' }}>Danh mục dòng tiền (đã có)</td>
                  <td style={{ textAlign: 'right', padding: '6px 8px' }}>{result.categoriesSkipped}</td>
                </tr>
                <tr style={{ borderBottom: '1px solid #f0f0f0' }}>
                  <td style={{ padding: '6px 8px' }}>Phiên bản kế hoạch</td>
                  <td style={{ textAlign: 'right', padding: '6px 8px' }}>{result.planCreated}</td>
                </tr>
                <tr>
                  <td style={{ padding: '6px 8px' }}>Dòng dự báo</td>
                  <td style={{ textAlign: 'right', padding: '6px 8px' }}>{result.planLinesCreated}</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      )}

      {result && (
        <div style={{ marginBottom: 24 }}>
          <h2 style={{ fontSize: 16, fontWeight: 600, marginBottom: 8 }}>Mở báo cáo kiểm tra</h2>
          <ul style={{ margin: 0, paddingLeft: 20, fontSize: 13, lineHeight: 1.8 }}>
            {REPORT_LINKS.map(r => (
              <li key={r.url}>
                <Link to={r.url}>{r.label}</Link>
              </li>
            ))}
          </ul>
          <p style={{ margin: '12px 0 0', fontSize: 12, color: 'var(--color-text-secondary, #6c757d)' }}>
            API: <code>POST /fpc/dev/sample-data?month=&amp;year=</code> · chỉ Development/Docker (DevAuth).
          </p>
        </div>
      )}

      {/* ── Demo report links (always visible) ── */}
      <div style={{ marginBottom: 24, padding: 16, borderRadius: 8, border: '1px dashed #8b5cf6', background: '#faf5ff' }}>
        <h2 style={{ fontSize: 16, fontWeight: 600, marginBottom: 8, color: '#6b21a8' }}>
          <i className="fas fa-desktop" style={{ marginRight: 8 }} />
          FPC — Báo cáo mẫu khách hàng xác nhận
        </h2>
        <p style={{ margin: '0 0 12px', fontSize: 13, lineHeight: 1.5, color: '#6b21a8' }}>
          Dữ liệu mô phỏng — không cần kết nối hệ thống. Dùng trình bày với khách hàng.
        </p>
        <ul style={{ margin: 0, paddingLeft: 20, fontSize: 13, lineHeight: 1.8 }}>
          {DEMO_LINKS.map(r => (
            <li key={r.url}>
              <Link to={r.url} style={{ fontWeight: 600, color: '#6b21a8' }}>{r.label}</Link>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default DevFpcSampleDataPage;
